import{_ as d,o as e,c as r,a2 as a}from"./chunks/framework.ZhLefgN8.js";const g=JSON.parse('{"title":"搜索","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"app-guide/search.md","filePath":"zh-CN/app-guide/search.md"}'),o={name:"app-guide/search.md"};function i(l,t,n,c,s,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="搜索" tabindex="-1">搜索 <a class="header-anchor" href="#搜索" aria-label="Permalink to &quot;搜索&quot;">​</a></h1><p>搜索是 App 内的统一检索入口，点击任意页面右上角的搜索图标（🔍）进入。支持股票标的、内容资讯和功能工具的综合搜索。</p><h2 id="搜索框" tabindex="-1">搜索框 <a class="header-anchor" href="#搜索框" aria-label="Permalink to &quot;搜索框&quot;">​</a></h2><p>输入框支持：</p><ul><li><strong>股票代码</strong>：如 <code>00700</code>、<code>AAPL</code>、<code>AMD260417P195000</code>（期权合约）；港股代码支持补零识别，输入 <code>700</code> 或 <code>00700</code> 均可找到腾讯控股</li><li><strong>公司名称</strong>：中英文均可，如「腾讯」「Apple」</li><li><strong>投资相关问题</strong>：自然语言提问，由 LongbridgeAI 解答</li></ul><p>期权合约可直接输入完整代码（如 <code>AMD260417P195000</code>），也可先输入正股代码（如 <code>AMD</code>），进入详情页选择「期权链」标签查看所有合约。搜索历史记录右侧有清除图标，可单条删除或一键清空全部历史。</p><h2 id="longbridgeai" tabindex="-1">LongbridgeAI <a class="header-anchor" href="#longbridgeai" aria-label="Permalink to &quot;LongbridgeAI&quot;">​</a></h2><p>搜索页顶部固定展示 LongbridgeAI 对话入口，可直接向 AI 提问投资相关问题，例如：</p><ul><li>「最近有哪些值得关注的港股？」</li><li>「解释一下市盈率（P/E）」</li><li>「这只股票的基本面怎么样？」</li></ul><blockquote><p>LongbridgeAI 与普通搜索的区别：普通搜索返回匹配的股票、新闻、工具等结构化结果；LongbridgeAI 回答开放性问题、解释概念、提供分析，适合需要解读的场景。</p></blockquote><h2 id="快捷工具入口" tabindex="-1">快捷工具入口 <a class="header-anchor" href="#快捷工具入口" aria-label="Permalink to &quot;快捷工具入口&quot;">​</a></h2><p>搜索框下方横向滚动的功能快捷入口：</p><table tabindex="0"><thead><tr><th>工具</th><th>说明</th></tr></thead><tbody><tr><td>期权榜</td><td>当日期权成交活跃排行</td></tr><tr><td>美股定投</td><td>设置美股定期定额买入计划</td></tr><tr><td>桌面端</td><td>Longbridge Pro 客户端介绍</td></tr><tr><td>美股排行榜</td><td>涨跌幅、成交量等多维排行</td></tr><tr><td>股票 VS</td><td>两只股票横向对比</td></tr><tr><td>热门股单</td><td>当前热门主题股单</td></tr><tr><td>深度数据</td><td>机构研报入口</td></tr><tr><td>选股器</td><td>多条件股票筛选</td></tr><tr><td>财经日历</td><td>经济数据与财报发布日程（点击事件旁的铃铛图标可设置提醒，触发时 App 推送通知）</td></tr><tr><td>货币基金</td><td>余额通/货币基金入口</td></tr><tr><td>结构化产品</td><td>雪球、票据等产品</td></tr><tr><td>私募基金</td><td>私募产品入口</td></tr></tbody></table><h2 id="热门股票" tabindex="-1">热门股票 <a class="header-anchor" href="#热门股票" aria-label="Permalink to &quot;热门股票&quot;">​</a></h2><p>页面中部展示港股和美股当日热门标的排行，显示排名、代码、名称和最新涨跌幅，点击直接跳转标的详情页。</p><h2 id="搜索结果" tabindex="-1">搜索结果 <a class="header-anchor" href="#搜索结果" aria-label="Permalink to &quot;搜索结果&quot;">​</a></h2><p>输入关键词后，结果页分类展示：</p><ul><li><strong>股票卡片</strong>：名称、代码、最新价、涨跌幅，点击进入详情页</li><li><strong>相关资讯</strong>：与该股票相关的新闻文章</li><li><strong>相关股单 / 用户</strong>：持有或讨论该标的的股单和社区用户</li></ul>',18)])])}const u=d(o,[["render",i]]);export{g as __pageData,u as default};
